// Step 1: Create/Open file
fd = open("data.txt", O_RDWR | O_CREAT, 0644)
IF fd == -1 THEN
 PRINT "Error opening file"
 EXIT
END IF

// Step 2: Write initial data
bytesWritten = write(fd, "Hello World", 11)
// file position now at 11

// Step 3: Seek to beginning
position = lseek(fd, 0, SEEK_SET)
// position = 0

// Step 4: Read data into buffer
bytesRead = read(fd, buffer, 11)
// file position now at 11, buffer contains "Hello World"

// Step 5: Seek to end and append
position = lseek(fd, 0, SEEK_END)
// position = 11
bytesWritten = write(fd, " More Text", 10)
// file now 21 bytes total

// Step 6: Close file
close(fd)

// Process A: Acquire shared lock to read
fd = open("shared.txt", O_RDWR)

// Acquire shared (read) lock
result = flock(fd, LOCK_SH)
IF result == 0 THEN
 // Read file contents
 WHILE read(fd, buffer, 1024) > 0 DO
 process(buffer)
 END WHILE

 // Release lock
 flock(fd, LOCK_UN)
END IF

// Process B: Acquire exclusive lock to write
fd = open("shared.txt", O_RDWR)

// Try to acquire exclusive (write) lock (blocks until available)
result = flock(fd, LOCK_EX)
IF result == 0 THEN
 // Seek to position and write
 lseek(fd, 0, SEEK_SET)
 write(fd, newData, dataSize)

 // Release lock
 flock(fd, LOCK_UN)
END IF

close(fd)

// Parent process
parent_fd = open("common.txt", O_RDWR | O_CREAT, 0644)
// parent_fd = 3 (first available)

// Write initial data
write(parent_fd, "Parent data", 12)

// Fork to create child
child_pid = fork()

IF child_pid == 0 THEN
 // Child process - inherits copy of file descriptor 3
 // But has its own file position pointer!

 // Child reads - will read from position 12 (shared offset!)
 lseek(parent_fd, 0, SEEK_SET) // Reset to start
 bytesRead = read(parent_fd, buffer, 100)
 PRINT "Child read: " + buffer

 // Child writes at current position
 write(parent_fd, "Child write", 11)

 // Child closes - parent's fd still valid!
 close(parent_fd)

ELSE THEN
 // Parent process
 // Wait for child
 wait(NULL)

 // Parent reads from position 23 (after child's write)
 lseek(parent_fd, 0, SEEK_SET)
 bytesRead = read(parent_fd, buffer, 100)
 PRINT "Parent read: " + buffer

 close(parent_fd)
END IF
